function isPeepingChara(keyName)
{
	if(! game.party.members.has(o.マックス)) return false;
	if(! game.party.status.has(o.透視)) return false;
	for(var i = 0; i < game.waitingMembers.count; i++)
	{
		var chr = game.waitingMembers[i];
		if(chr.keyName != keyName) continue;
		game.curChara = chr;
		return true;
	}
	return false;
}

